import React, { useEffect, useState } from 'react';
import api from '../../services/api';
import Toast from '../common/Toast';
import Loader from '../common/Loader';

interface Feedback {
  id: number;
  rating: number;
  wordRating: string;
  topics: string[];
  createdAt: string;
}

const FeedbackList: React.FC = () => {
  const [feedbacks, setFeedbacks] = useState<Feedback[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showToast, setShowToast] = useState(false);
  const [toastMessage, setToastMessage] = useState('');
  const [toastType, setToastType] = useState<'success' | 'error'>('success');
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editData, setEditData] = useState({ rating: 0, wordRating: '', topics: [] as string[] });

  const wordRatings = ['Giddu-galeessa', 'Gaarii', 'Quubsaa', 'Baayee Gaarii', 'Ol-aanaa'];
  const topics = [
    'Saffisa tajaajila mootummaa fi hojii daldalaa fooyyessuu',
    'Hojii haaraa uumuu fi dinagdee naannoo guddisuu',
    'Malaammaltummaa hirisuu fi iftoomina dabaluu',
    'Jireenya qotee bulaa ammayyeessuu fi omishaa dabaluu',
  ];

  useEffect(() => {
    fetchFeedbacks();
  }, []);

  const fetchFeedbacks = async () => {
    try {
      const response = await api.get('/api/feedback');
      // Check if response is an array, if not, try to extract data
      let data = response.data;
      if (data && !Array.isArray(data)) {
        // If data has a data property that is an array
        if (data.data && Array.isArray(data.data)) {
          data = data.data;
        } else if (data.success && Array.isArray(data.data)) {
          data = data.data;
        } else {
          // If it's an object but not array, convert to empty array
          console.warn('API response is not an array:', data);
          data = [];
        }
      }
      setFeedbacks(data || []);
      setError('');
    } catch (err) {
      console.error('Error fetching feedbacks:', err);
      setError('Failed to load feedbacks');
    } finally {
      setLoading(false);
    }
  };

  const showMessage = (message: string, type: 'success' | 'error') => {
    setToastMessage(message);
    setToastType(type);
    setShowToast(true);
    setTimeout(() => setShowToast(false), 3000);
  };

  const handleEdit = (feedback: Feedback) => {
    setEditingId(feedback.id);
    setEditData({
      rating: feedback.rating,
      wordRating: feedback.wordRating,
      topics: [...feedback.topics],
    });
  };

  const handleUpdate = async (id: number) => {
    try {
      await api.put(`/api/feedback/${id}`, editData);
      showMessage('Feedback updated successfully!', 'success');
      setEditingId(null);
      fetchFeedbacks();
    } catch (err) {
      showMessage('Failed to update feedback', 'error');
    }
  };

  const handleDelete = async (id: number) => {
    if (!window.confirm('Are you sure you want to delete this feedback?')) return;
    try {
      await api.delete(`/api/feedback/${id}`);
      showMessage('Feedback deleted successfully!', 'success');
      fetchFeedbacks();
    } catch (err) {
      showMessage('Failed to delete feedback', 'error');
    }
  };

  const handleTopicToggle = (topic: string) => {
    setEditData(prev => ({
      ...prev,
      topics: prev.topics.includes(topic)
        ? prev.topics.filter(t => t !== topic)
        : [...prev.topics, topic],
    }));
  };

  if (loading) return <Loader fullScreen />;
  if (error) return <div style={styles.error}>{error}</div>;
  if (!feedbacks || feedbacks.length === 0) {
    return (
      <div style={styles.container}>
        <h2 style={styles.title}>📊 All Feedback Submissions</h2>
        <div style={styles.emptyState}>
          <p>No feedback yet. Be the first to submit!</p>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <h2 style={styles.title}>📊 All Feedback Submissions</h2>
      <p style={styles.subtitle}>Manage and moderate user feedback</p>

      {showToast && (
        <Toast message={toastMessage} type={toastType} onClose={() => setShowToast(false)} />
      )}

      <div style={styles.tableWrapper}>
        <table style={styles.table}>
          <thead>
            <tr>
              <th style={styles.th}>ID</th>
              <th style={styles.th}>Rating</th>
              <th style={styles.th}>Word Rating</th>
              <th style={styles.th}>Topics</th>
              <th style={styles.th}>Date</th>
              <th style={styles.th}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {feedbacks.map((fb) => (
              <tr key={fb.id}>
                <td style={styles.td}>{fb.id}</td>
                <td style={styles.td}>
                  {editingId === fb.id ? (
                    <select
                      value={editData.rating}
                      onChange={(e) => setEditData({ ...editData, rating: parseInt(e.target.value) })}
                      style={styles.select}
                    >
                      {[1, 2, 3, 4, 5].map(n => <option key={n} value={n}>{n}</option>)}
                    </select>
                  ) : (
                    <span style={styles.rating}>{fb.rating} ⭐</span>
                  )}
                </td>
                <td style={styles.td}>
                  {editingId === fb.id ? (
                    <select
                      value={editData.wordRating}
                      onChange={(e) => setEditData({ ...editData, wordRating: e.target.value })}
                      style={styles.select}
                    >
                      {wordRatings.map(w => <option key={w} value={w}>{w}</option>)}
                    </select>
                  ) : (
                    fb.wordRating
                  )}
                </td>
                <td style={styles.td}>
                  {editingId === fb.id ? (
                    <div style={styles.topicCheckboxes}>
                      {topics.map(topic => (
                        <label key={topic} style={styles.topicLabel}>
                          <input
                            type="checkbox"
                            checked={editData.topics.includes(topic)}
                            onChange={() => handleTopicToggle(topic)}
                          />
                          <span style={styles.topicText}>{topic.substring(0, 40)}...</span>
                        </label>
                      ))}
                    </div>
                  ) : (
                    <div style={styles.topics}>
                      {fb.topics && fb.topics.map((t, i) => (
                        <span key={i} style={styles.topicTag}>{t.substring(0, 30)}...</span>
                      ))}
                    </div>
                  )}
                </td>
                <td style={styles.td}>{new Date(fb.createdAt).toLocaleDateString()}</td>
                <td style={styles.td}>
                  {editingId === fb.id ? (
                    <>
                      <button onClick={() => handleUpdate(fb.id)} style={styles.saveBtn}>💾 Save</button>
                      <button onClick={() => setEditingId(null)} style={styles.cancelBtn}>❌ Cancel</button>
                    </>
                  ) : (
                    <>
                      <button onClick={() => handleEdit(fb)} style={styles.editBtn}>✏️ Edit</button>
                      <button onClick={() => handleDelete(fb.id)} style={styles.deleteBtn}>🗑️ Delete</button>
                    </>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
